proof_block:
// The synthetic ensures has the shape `P(r1, r2) ==> det_eq(r1, r2)`
// where r1 / r2 are *unconstrained* proof-fn parameters — i.e. the
// per-run ensures of `thread_to_page` are only available *under* the
// antecedent P. Asserting `r1.0 == thread_ptr` etc. at top level is
// therefore unprovable, which is what felled attempt 01.
//
// Wrap the whole proof in `if P { ... }` so each subsequent `assert`
// is checked against the path condition that includes P. Inside the
// branch we then:
//   * derive `r1.0 == r2.0` via transitivity through `thread_ptr`;
//   * pull both `r1.1@` / `r2.1@` ensures back into scope so the
//     triggers on the closed spec fns `addr()` / `is_init()` line up
//     for the two runs;
//   * close the `PointsTo<...>` view-equality via the structural
//     extensionality operator `=~=`, also asserting equality on the
//     individual observables in case Verus needs them as separate
//     trigger sites.
//
// Outside the branch the path-merge gives z3 exactly
// `P ==> det_eq(r1, r2)`, which is the ensures.
if (r1.0 == thread_ptr) && (r1.1@.is_init()) && (r1.1@.addr() == r1.0)
    && (r2.0 == thread_ptr) && (r2.1@.is_init()) && (r2.1@.addr() == r2.0)
{
    // First component: both equal thread_ptr by hypothesis.
    assert(r1.0 == thread_ptr);
    assert(r2.0 == thread_ptr);
    assert(r1.0 == r2.0);

    // Per-run facts about the PointsTo view — re-asserted so that the
    // triggers on `r1.1@` / `r2.1@` fire for each side.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.addr() == r1.0);
    assert(r2.1@.addr() == r2.0);

    // Pairwise observable equalities.
    assert(r1.1@.addr() == r2.1@.addr());
    assert(r1.1@.is_init() == r2.1@.is_init());

    // Lift the per-observable equalities to structural equality on
    // the `PointsTo` view. `=~=` is Verus' built-in extensional
    // equality and gives us `==` on the view directly afterwards.
    assert(r1.1@ =~= r2.1@);
    assert(r1.1@ == r2.1@);

    // Final consequent, so z3 sees the goal explicitly at the end of
    // the only branch where it has to hold.
    assert(det_thread_to_page_equal(r1, r2));
}
